// frontend/src/pages/AboutPage.js
import React, { useState } from 'react';

const quizData = [
  {
    question: 'Who is the Philippine National Hero that Rizal Park is named after?',
    options: ['Andres Bonifacio', 'Jose Rizal', 'Emilio Aguinaldo', 'Apolinario Mabini'],
    answer: 1,
  },
  {
    question: 'In what year did the Spanish first arrive in the Philippines?',
    options: ['1492', '1521', '1898', '1945'],
    answer: 1,
  },
  {
    question: "Which famous 19th-century painting by Juan Luna is housed in the National Museum of Fine Arts?",
    options: ['The Parisian Life', 'Spoliarium', 'Antipolo', 'Making of the Philippine Flag'],
    answer: 1,
  },
  {
    question: 'Which UNESCO World Heritage City is famous for its preserved Spanish-era cobblestone streets?',
    options: ['Cebu City', 'Vigan City', 'Baguio City', 'Zamboanga City'],
    answer: 1,
  },
  {
    question: "The 'Tree of Life' structure is the architectural centerpiece of which museum?",
    options: [
      'Museum of Fine Arts',
      'National Museum of Natural History',
      'National Museum of Anthropology',
      'Ayala Museum',
    ],
    answer: 1,
  },
];

const LETTERS = ['A', 'B', 'C', 'D'];

const AboutPage = () => {
  const [quizStarted, setQuizStarted]   = useState(false);
  const [quizHidden,  setQuizHidden]    = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [score,       setScore]         = useState(0);
  const [showResults, setShowResults]   = useState(false);
  const [selectedOption, setSelectedOption] = useState(null);
  const [feedback, setFeedback] = useState({ text: '', type: '' });

  const handleSubmit = () => {
    const correct = selectedOption === quizData[currentQuestion].answer;
    if (correct) setScore(s => s + 1);
    setFeedback({
      text: correct
        ? '✨ Correct!'
        : `✗ The answer was: ${quizData[currentQuestion].options[quizData[currentQuestion].answer]}`,
      type: correct ? 'correct' : 'wrong',
    });
    setTimeout(() => {
      setFeedback({ text: '', type: '' });
      setSelectedOption(null);
      if (currentQuestion + 1 < quizData.length) setCurrentQuestion(q => q + 1);
      else setShowResults(true);
    }, 1600);
  };

  const resetQuiz = () => {
    setQuizStarted(false); setQuizHidden(false);
    setCurrentQuestion(0); setScore(0);
    setShowResults(false); setSelectedOption(null);
    setFeedback({ text: '', type: '' });
  };

  const getResultMessage = () => {
    if (score === quizData.length) return 'Perfect score! A true heritage enthusiast.';
    if (score >= 3) return 'Great job! You know your Philippine history well.';
    if (score >= 1) return 'Good effort! Keep exploring the museums.';
    return 'Keep visiting — the artifacts have more to teach you.';
  };

  const progress = (currentQuestion / quizData.length) * 100;

  return (
    <div className="content">
      <h2>About the Museum Journal</h2>
      <p>
        "Leaving the museum is always a sensory shock. You move from the hushed, cathedral-like
        silence of the galleries into the gold-tinted humidity of Rizal Park. The distant sound of the
        dancing fountain and the scent of street vendors selling isaw and sorbetes act as a bridge,
        reminding me that the history I just saw inside is still breathing in the people walking outside."
      </p>
      <p>
        In our fast-paced, digital world, museums and history remind us to slow down. They teach us
        that we are part of a much larger narrative. Whether it's the grand tragedy of Juan Luna's
        Spoliarium or the quiet beauty of a sunset at Rizal Park, history is the mirror we use to
        understand who we are today.
      </p>
      <p>
        My journal is an invitation to you: Don't just visit a museum to see the sights. Visit to
        "lose your head and keep your eyes open." You might just find a story that changes how you
        see the world.
      </p>

      <section>
        <h3>My Timeline</h3>
        <ul>
          <li><strong>2020:</strong> First Museum Visit (National Museum) — Ignited my passion for history.</li>
          <li><strong>2022:</strong> Joined Art Club — Focused on sketching artifacts.</li>
          <li><strong>2024:</strong> Provincial Travels — Explored heritage sites in Vigan &amp; Baguio.</li>
        </ul>
      </section>

      <hr style={{ margin: '32px 0', border: 'none', borderTop: '1px solid #d2b48c' }} />

      {/* ── Quiz ── */}
      <div id="trivia-wrapper">
        <div className="trivia-header">
          <span className="trivia-header-icon">🏛️</span>
          <h2>Quick Museum Trivia</h2>
        </div>

        <div className="trivia-body">
          {quizHidden ? (
            <p className="trivia-skipped">Trivia skipped — enjoy reading the journal!</p>

          ) : !quizStarted ? (
            <div style={{ textAlign: 'center' }}>
              <p className="trivia-start-text">
                Think you know your Philippine heritage? Test yourself with {quizData.length} quick questions.
              </p>
              <button className="quiz-btn" onClick={() => setQuizStarted(true)}>
                Yes, Let's Play!
              </button>
              <button className="quiz-btn secondary" onClick={() => setQuizHidden(true)}>
                No, Thanks
              </button>
            </div>

          ) : showResults ? (
            <div className="trivia-results">
              <div className="trivia-score-circle">
                <span className="score-num">{score}</span>
                <span className="score-denom">/ {quizData.length}</span>
              </div>
              <h3>Quiz Complete!</h3>
              <p>{getResultMessage()}</p>
              <button className="quiz-btn" onClick={resetQuiz}>Play Again</button>
            </div>

          ) : (
            <div>
              {/* Progress bar */}
              <div className="trivia-progress-bar">
                <div className="trivia-progress-fill" style={{ width: `${progress}%` }} />
              </div>

              <div className="trivia-counter">
                Question {currentQuestion + 1} of {quizData.length}
              </div>

              <p className="trivia-question">
                {quizData[currentQuestion].question}
              </p>

              <div>
                {quizData[currentQuestion].options.map((option, index) => (
                  <div
                    key={index}
                    className={`option ${selectedOption === index ? 'selected' : ''}`}
                    onClick={() => { if (!feedback.text) setSelectedOption(index); }}
                  >
                    <span className="option-letter">{LETTERS[index]}</span>
                    {option}
                  </div>
                ))}
              </div>

              <button
                className="quiz-btn"
                style={{ marginTop: '16px' }}
                onClick={handleSubmit}
                disabled={selectedOption === null || feedback.text !== ''}
              >
                Submit Answer
              </button>

              {feedback.text && (
                <div className={`trivia-feedback ${feedback.type}`}>
                  {feedback.text}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      <section style={{ marginTop: '40px' }}>
        <h3>Our Goal</h3>
        <ul>
          <li>Document historic artifacts.</li>
          <li>Share travel tips for museum enthusiasts.</li>
          <li>Inspire others to explore Philippine heritage.</li>
        </ul>
      </section>
    </div>
  );
};

export default AboutPage;
